INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES ("リリ", 24001, 1, 321, 0, 40011, 1, 2, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, 125801);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES ("クリア", 24001, 1, 322, 0, 40011, 2, 2, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 1, 126001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES ("プレシア", 24001, 1, 323, 0, 40011, 3, 2, "んーと。\nこれ、あげる。\nはい", 1, 126101);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES ("リリ", 24001, 1, 324, 0, 40011, 4, 2, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 125801);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES ("クリア", 24001, 1, 325, 0, 40011, 5, 2, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 126001);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES ("プレシア", 24001, 1, 326, 0, 40011, 6, 2, "お兄。\nきてくれて、うれしい", 2, 126101);
